module top_module(/*AUTOARG*/
   // Inputs
   reset_clk,
   data_in,
   enable,
   // Outputs
   data_out
   );input reset_clk;
   input [3:0] data_in;
   input enable;
   output reg [2:0] data_out;

   initial data_out = 0;

   always @(posedge reset_clk) begin
      if (enable == 1'b1) begin
         data_out <= data_in + 3'b010; // 2 in binary is 010
      end else begin
         data_out <= data_in;
      end
   end

endmodule
